955	/*
956	 * Try to read the location of the git directory from the .git file,
957	 * return path to git directory if found. The return value comes from
958	 * a shared buffer.
959	 *
960	 * On failure, if return_error_code is not NULL, return_error_code
961	 * will be set to an error code and NULL will be returned. If
962	 * return_error_code is NULL the function will die instead (for most
963	 * cases).
964	 */
965	const char *read_gitfile_gently(const char *path, int *return_error_code)
966	{
967		const int max_file_size = 1 << 20;  /* 1MB */
968		int error_code = 0;
969		char *buf = NULL;
970		char *dir = NULL;
971		const char *slash;
972		struct stat st;
973		int fd;
974		ssize_t len;
975		static struct strbuf realpath = STRBUF_INIT;
976	
977		if (stat(path, &st)) {
978			if (errno == ENOENT || errno == ENOTDIR)
979				error_code = READ_GITFILE_ERR_MISSING;
980			else
981				error_code = READ_GITFILE_ERR_STAT_FAILED;
982			goto cleanup_return;
983		}
984		if (S_ISDIR(st.st_mode)) {
985			error_code = READ_GITFILE_ERR_IS_A_DIR;
986			goto cleanup_return;
987		}
988		if (!S_ISREG(st.st_mode)) {
989			error_code = READ_GITFILE_ERR_NOT_A_FILE;
990			goto cleanup_return;
991		}
992		if (st.st_size > max_file_size) {
993			error_code = READ_GITFILE_ERR_TOO_LARGE;
994			goto cleanup_return;
995		}
996		fd = open(path, O_RDONLY);
997		if (fd < 0) {
998			error_code = READ_GITFILE_ERR_OPEN_FAILED;
999			goto cleanup_return;
1000		}
1001		buf = xmallocz(st.st_size);
1002		len = read_in_full(fd, buf, st.st_size);
1003		close(fd);
1004		if (len != st.st_size) {
