1017		}
1018		buf[len] = '\0';
1019		dir = buf + 8;
1020	
1021		if (!is_absolute_path(dir) && (slash = strrchr(path, '/'))) {
1022			size_t pathlen = slash+1 - path;
1023			dir = xstrfmt("%.*s%.*s", (int)pathlen, path,
1024				      (int)(len - 8), buf + 8);
1025			free(buf);
1026			buf = dir;
1027		}
1028		if (!is_git_directory(dir)) {
1029			error_code = READ_GITFILE_ERR_NOT_A_REPO;
1030			goto cleanup_return;
1031		}
1032	
1033		strbuf_realpath(&realpath, dir, 1);
1034		path = realpath.buf;
